<script setup>
import { ref, computed, onMounted } from "vue";

const props = defineProps(["wslogs"]);

const hideOverlay = ref(false);
const items = ref([]);
const logFileDialog = ref(false);
const selectedLogFileData = ref(null);

let headers = ref([
  { title: "Script", value: "script", width: "7%", align: "center" },
  { title: "Scenario", value: "scenario", width: "7%", align: "center" },
  { title: "Iteration", value: "iteration", width: "6%", align: "center" },
  { title: "Row", value: "row", width: "3%", align: "center" },
  { title: "URL", value: "url", width: "30%", align: "center" },
  { title: "Method", value: "method", width: "6%", align: "center" },
  { title: "Req Len", value: "reqLen", width: "6%", align: "center" },
  { title: "Return Code", value: "returnCode", width: "6%", align: "center" },
  {
    title: "Return Status",
    value: "returnStatus",
    width: "6%",
    align: "center",
  },
  { title: "TTFB", value: "TTFB", width: "6%", align: "center" },
  {
    title: "Ellapsed Time",
    value: "ellapsedTime",
    width: "6%",
    align: "center",
  },
  { title: "Res Len", value: "resLen", width: "6%", align: "center" },
  { title: "File", value: "relativeFilePath", width: "3%", align: "center" },
  { title: "View File", value: "content", width: "3%", align: "center" },
]);
const search = ref("");
// const itemsPerPage = 5;
// const page = ref(1);
const fileInfo = ref(null);

// Dropdown options
const methods = ref([]); // Example methods
const statusCodes = ref([]); // Example status codes

// Selected options
const selectedMethods = ref([]);
const selectedStatusCodes = ref([]);

onMounted(() => {
  createTableData();
});

const filteredItems = computed(() => {
  console.log(items.value);
  return items.value.filter((item) => {
    const methodMatch = selectedMethods.value.length
      ? selectedMethods.value.includes(item.method)
      : false;
    const statusCodeMatch = selectedStatusCodes.value.length
      ? selectedStatusCodes.value.includes(item.returnCode)
      : false;
    return methodMatch && statusCodeMatch;
  });
});

const extractRowNumber = (row) => row.slice(1);

const replaceWithBr = (str) => {
  return str.replace(/\n/g, "<br />");
};

const createTableData = () => {
  const isDetailsPresent = props.wslogs.details && props.wslogs.details.length;
  const isSummaryPresent =
    props.wslogs.summary &&
    props.wslogs.summary.records &&
    props.wslogs.summary.records.length;

  if (props.wslogs && isDetailsPresent && isSummaryPresent) {
    items.value = props.wslogs.details.map((detail) => {
      // const scenarioTxt = detail.repeatUntil ? `${detail.scenario} ${detail.row}` : detail.scenario;
      // const rowNo = detail.repeatUntil ? extractRowNumber(detail.repeatUntil) : extractRowNumber(detail.row);

      const matchingRecord = props.wslogs.summary.records.find(
        (record) =>
          record[1] === detail.invokeFrom &&
          record[2] === detail.scenario &&
          record[3] === extractRowNumber(detail.row) &&
          record[4] === detail.url &&
          record[5] === detail.method &&
          parseInt(record[7]) === detail.returnCode
      );

      // if (matchingRecord) {
      return {
        script: detail.script,
        scenario: matchingRecord[2],
        iteration: detail.iteration,
        row: matchingRecord[3],
        url: matchingRecord[4],
        method: matchingRecord[5],
        reqLen: matchingRecord[6],
        returnCode: matchingRecord[7],
        returnStatus: matchingRecord[8],
        TTFB: matchingRecord[9],
        ellapsedTime: matchingRecord[10],
        resLen: matchingRecord[11],
        file: detail.file,
        relativeFilePath: detail.relativeFilePath,
        content: detail.content,
      };
      // }
    });

    // items.value = props.wslogs.details;
    // items.value = [...detailsArray];
  } else if (props.wslogs && isDetailsPresent && !isSummaryPresent) {
    headers.value = [
      { title: "Script", value: "script", width: "8%", align: "center" },
      { title: "Scenario", value: "scenario", width: "8%", align: "center" },
      { title: "Iteration", value: "iteration", width: "7%", align: "center" },
      { title: "Row", value: "row", width: "3%", align: "center" },
      { title: "URL", value: "url", width: "30%", align: "center" },
      { title: "Method", value: "method", width: "6%", align: "center" },
      {
        title: "Return Code",
        value: "returnCode",
        width: "6%",
        align: "center",
      },
      {
        title: "File",
        value: "relativeFilePath",
        width: "3%",
        align: "center",
      },
      { title: "View File", value: "content", width: "3%", align: "center" },
    ];
    items.value = props.wslogs.details.map((detail) => {
      // const scenarioTxt = detail.repeatUntil ? `${detail.scenario} ${detail.row}` : detail.scenario;
      // const rowNo = detail.repeatUntil ? extractRowNumber(detail.repeatUntil) : extractRowNumber(detail.row);

      return {
        script: detail.script,
        scenario: detail.scenario,
        iteration: detail.iteration,
        row: extractRowNumber(detail.row),
        url: detail.url,
        method: detail.method,
        returnCode: detail.returnCode,
        file: detail.file,
        relativeFilePath: detail.relativeFilePath,
        content: detail.content,
      };
    });
  } else if (props.wslogs && !isDetailsPresent && isSummaryPresent) {
    headers.value = [
      { title: "Output", value: "output", width: "8%", align: "center" },
      { title: "Scenario", value: "scenario", width: "8%", align: "center" },
      { title: "Row", value: "row", width: "3%", align: "center" },
      { title: "URL", value: "url", width: "30%", align: "center" },
      { title: "Method", value: "method", width: "6%", align: "center" },
      { title: "Req Len", value: "reqLen", width: "6%", align: "center" },
      {
        title: "Return Code",
        value: "returnCode",
        width: "6%",
        align: "center",
      },
      {
        title: "Return Status",
        value: "returnStatus",
        width: "6%",
        align: "center",
      },
      { title: "TTFB", value: "TTFB", width: "6%", align: "center" },
      {
        title: "Ellapsed Time",
        value: "ellapsedTime",
        width: "6%",
        align: "center",
      },
      { title: "Res Len", value: "resLen", width: "6%", align: "center" },
    ];
    items.value = props.wslogs.summary.records.map((record) => {
      return {
        output: record[1],
        scenario: record[2],
        row: record[3],
        url: record[4],
        method: record[5],
        reqLen: record[6],
        returnCode: record[7],
        returnStatus: record[8],
        TTFB: record[9],
        ellapsedTime: record[10],
        resLen: record[11],
      };
    });
  }

  if (props.wslogs && props.wslogs.summary) {
    fileInfo.value = props.wslogs.summary;
  }

  // statusCodes.value = props.wslogs.details.map((item) => item.returnCode);
  // methods.value = [
  //   ...new Set(props.wslogs.details.map((item) => item.method)),
  // ];
  // statusCodes.value = [
  //   ...new Set(props.wslogs.details.map((item) => item.returnCode)),
  // ];
  methods.value = [...new Set(items.value.map((item) => item.method))];
  statusCodes.value = [...new Set(items.value.map((item) => item.returnCode))];

  selectedMethods.value = methods.value;
  selectedStatusCodes.value = statusCodes.value;
};

const openLogFileContentInDialog = (rowItem) => {
  logFileDialog.value = true;
  selectedLogFileData.value = {
    ...rowItem,
    content: replaceWithBr(rowItem.content),
  };
};

const getReturnCodeChipColor = (returnCode) => {
  // switch (returnCode) {
  //   case 200:
  //     return "green";
  //   case 201:
  //     return "blue";
  //   case 403:
  //     return "red";
  //   default:
  //     return "grey";
  // }

  if (returnCode >= 200 && returnCode <= 299) {
    return "returnCode200";
  } else if (returnCode >= 300 && returnCode <= 399) {
    return "returnCode300";
  } else if (returnCode >= 400 && returnCode <= 499) {
    return "returnCode400";
  } else if (returnCode >= 500 && returnCode <= 599) {
    return "returnCode500";
  } else {
    return "";
  }
};

// const getMethodChipColor = (method) => {
//   switch (method) {
//     case "GET":
//       return "#65b3fb";
//     case "POST":
//       return "#4fcc93";
//     case "PUT":
//       return "#faa13d";
//     case "PATCH":
//       return "#57e3c3";
//     case "DELETE":
//       return "#f63e42";
//     case "HEAD":
//       return "#9027fa";
//     case "OPTIONS":
//       return "#0d5ca7";
//     default:
//       return "grey";
//   }
// };
</script>

