const extractTextsFromHTML = (htmlString) => {
  // Create a temporary DOM element
  const tempDiv = document.createElement("div");

  // Set the innerHTML of this element to the HTML string
  tempDiv.innerHTML = htmlString;

  // Use querySelector to find the specific paragraphs
  const boldParagraph = tempDiv.querySelector('p[style*="font-size: 28px;"]');
  const detailedParagraph = tempDiv.querySelector("h2 > p");

