    boldText: boldParagraph ? boldParagraph.textContent : "",
    detailedText: detailedParagraph ? detailedParagraph.textContent : "",
  };
};

function flattenExecutions(executions) {
  let flattenedArray = [];

  function recurseExecutions(execArray) {
    execArray.forEach((exec, index) => {
      // Calculate the duration in minutes and add it as a new property
      if (exec.startTime && exec.endTime) {
        exec.duration = calculateDuration(exec);
        exec.startDateAndTime = formatTimestampToDateTime(exec.startTime);
        exec.endDateAndTime = formatTimestampToDateTime(exec.endTime);
      }

      if (exec.passCount) {
        exec.successRate =
          ((exec.passCount / exec.totalSteps) * 100).toFixed(2) + " %";
      }

      flattenedArray.push(exec);

      // If there are nested executions, recurse into them
      if (exec.nestedExecutions && exec.nestedExecutions.length > 0) {
        recurseExecutions(exec.nestedExecutions);
      }
    });
  }

  recurseExecutions(executions);
  return flattenedArray;
}

async function addCalculatedPropsInExecution(execution) {
  // Calculate duration
  const duration = calculateDuration(execution);

  // Calculate success rate
  const successRate =
    ((execution.passCount / execution.totalSteps) * 100).toFixed(2) + " %";

  // Convert start time to human-readable format
  const startDateAndTime = new Date(execution.startTime).toLocaleString(
    "en-US",
    {
      year: "numeric",
      month: "2-digit",
      day: "2-digit",
      hour: "2-digit",
      minute: "2-digit",
      second: "2-digit",
      hour12: false,
    }
  );

  const endDateAndTime = new Date(execution.endTime).toLocaleString("en-US", {
    year: "numeric",
    month: "2-digit",
    day: "2-digit",
    hour: "2-digit",
    minute: "2-digit",
    second: "2-digit",
    hour12: false,
  });

  // Assign the calculated values to the execution object
  execution.duration = duration;
  execution.successRate = successRate;
  execution.startDateAndTime = startDateAndTime;
  execution.endDateAndTime = endDateAndTime;

  // If there are nested executions, calculate their details recursively
  if (execution.nestedExecutions && execution.nestedExecutions.length > 0) {
    execution.nestedExecutions.forEach(
      async (nestedExecution) =>
        await addCalculatedPropsInExecution(nestedExecution)
    );
  }
  executionDetailsAddedMoreProps.value = execution;
}

const formatTimestampToDateTime = (timestamp) => {
  const date = new Date(timestamp);

  const year = date.getFullYear();
  const month = `0${date.getMonth() + 1}`.slice(-2); // Months are zero-indexed
  const day = `0${date.getDate()}`.slice(-2);
  const hours = `0${date.getHours()}`.slice(-2);
  const minutes = `0${date.getMinutes()}`.slice(-2);
  const seconds = `0${date.getSeconds()}`.slice(-2);

  return `${year}/${month}/${day} ${hours}:${minutes}:${seconds}`;
};

const calculateDuration = (exec) => {
  const durationMs = exec.endTime - exec.startTime;
  const minutes = Math.floor(durationMs / 60000);
  const seconds = Math.floor((durationMs % 60000) / 1000);
  return minutes == 0 ? `${seconds} sec` : `${minutes} min ${seconds} sec`;
};

const extractDataFromExecutionDetail = (executionNode) => {
  const results = [];
  if (executionNode.nestedExecutions.length) {
    for (let i = 0; i < executionNode.nestedExecutions.length; i++) {
      const scriptNode = executionNode.nestedExecutions[i];
      if (scriptNode.nestedExecutions.length) {
        for (let j = 0; j < scriptNode.nestedExecutions.length; j++) {
          const iterationNode = scriptNode.nestedExecutions[j];
          if (iterationNode.nestedExecutions.length) {
            for (let k = 0; k < iterationNode.nestedExecutions.length; k++) {
              const scenarioNode = iterationNode.nestedExecutions[k];
              results.push({
                name: scenarioNode.name,
                scriptName: scriptNode.name || "", // Dynamic script name
                scriptSuccessRate: scriptNode.successRate,
                iterationSuccessRate: iterationNode.successRate,
                iterationIndex: j + 1,
                iterationTotal: scriptNode.nestedExecutions.length,
                scriptFile: scriptNode.scriptFile,
                dataFile: scriptNode.dataFile,
                duration: scenarioNode.duration,
                iterationDuration: iterationNode.duration,
                referenceDataExecutionLevel: executionNode.referenceData,
                referenceDataScriptLevel: scriptNode.referenceData,
                referenceDataIterationLevel: iterationNode.referenceData,
                referenceDataScenarioLevel: scenarioNode.referenceData,
                activities: getActivityDetails(scenarioNode.nestedExecutions),
                scriptStats: createStats(scriptNode),
                iterationStats: createStats(iterationNode),
                stats: createStats(scenarioNode),
                planName: scriptNode.planName || "",
              });
            }
          }
        }
      }
    }
  }
  return results;
};

function getActivityDetails(nestedExecutions) {
  let temp = [];

  nestedExecutions.forEach((node) => {
    temp.push({
      name: node.name,
      startDateAndTime: new Date(node.startTime).toLocaleString(),
      duration: node.duration,
      totalSteps: node.totalSteps,
      passCount: node.passCount,
      failCount: node.failCount,
      successRate: node.successRate,
      stepDetails: node.stepDetails,
    });
  });
  return temp;
}

