const removeDuplicates = (data) => {
  return Object.values(
    data.reduce((acc, item) => {
      const key = `${item.name}-${item.scriptName}-${item.iterationIndex}-${item.iterationTotal}`;
      if (!acc[key]) {
        acc[key] = item;
      }
      return acc;
    }, {})
  );
};

const mergeData = (data) => {
  // Helper function to merge scenarios
  const mergeScenarios = (scenarios) => {
    return scenarios.reduce((acc, scenario) => {
      const existingScenario = acc.find((s) => s.name === scenario.name);
      if (existingScenario) {
        existingScenario.activities.push(...scenario.activities);
      } else {
        acc.push({
          ...scenario,
          activities: [...scenario.activities],
        });
      }
      return acc;
    }, []);
  };

  // Group data by scriptName, iterationIndex, and iterationTotal
  const groupedData = data.reduce((acc, item) => {
    const key = `${item.scriptName}-${item.iterationIndex}-${item.iterationTotal}`;
    if (!acc[key]) {
      acc[key] = {
        scriptName: item.scriptName,
        scriptSuccessRate: item.scriptSuccessRate,
        iterationSuccessRate: item.iterationSuccessRate,
        iterationIndex: item.iterationIndex,
        iterationTotal: item.iterationTotal,
        iterationDuration: item.iterationDuration,
        scriptFile: item.scriptFile,
        dataFile: item.dataFile,
        referenceDataExecutionLevel: item.referenceDataExecutionLevel,
        referenceDataScriptLevel: item.referenceDataScriptLevel,
        referenceDataIterationLevel: item.referenceDataIterationLevel,
        scriptStats: item.scriptStats,
        iterationStats: item.iterationStats,
        scenarios: [],
        planName: item.planName,
      };
    }
    acc[key].scenarios.push(item);
    return acc;
  }, {});

  // Transform grouped data to desired format
  return Object.values(groupedData).map((group) => {
    return {
      scriptName: group.scriptName,
      scriptSuccessRate: group.scriptSuccessRate,
      iterationSuccessRate: group.iterationSuccessRate,
      iterationIndex: group.iterationIndex,
      iterationTotal: group.iterationTotal,
      iterationDuration: group.iterationDuration,
      referenceDataExecutionLevel: group.referenceDataExecutionLevel,
      referenceDataScriptLevel: group.referenceDataScriptLevel,
      referenceDataIterationLevel: group.referenceDataIterationLevel,
      scriptFile: group.scriptFile,
      dataFile: group.dataFile,
      scriptStats: group.scriptStats,
      iterationStats: group.iterationStats,
      scenarios: mergeScenarios(
        group.scenarios.map((item) => ({
          name: item.name,
          stats: item.stats,
          duration: item.duration,
          expanded: false,
          referenceDataScenarioLevel: item.referenceDataScenarioLevel,
          activities: item.activities,
        }))
      ),
      planName: group.planName,
    };
  });
};

const createStats = (node) => {
  return [
