<template>
  <div>
    <header class="header">
      <div class="logo-container">
        <div class="heading-section">
          <img :src="customerLogoPath" @error="onHeaderLogoErrorHandler" alt="Header Logo" class="logo" />
          <div class="heading">Test Report</div>
        </div>

        <div class="powered-by">
          <span>Powered by</span>
          <img src="accionlabs-logo.png" alt="Powered By Accion Logo" class="accion-logo" />
        </div>
      </div>
      <div class="chips-container">
        <div class="test-stats" v-if="testBasicDetails.length">
          <v-chip
            v-for="(test, index) in testBasicDetails"
            :key="index"
            class="test-chip"
            :class="getChipColorClass(test.name)"
            :prepend-icon="test.icon"
          >
            <strong>{{ test.name }}</strong
            >: {{ test.count }}
          </v-chip>
        </div>
      </div>
    </header>
  </div>
</template>

<script setup>
import { ref, onMounted, watch } from "vue";
// import { execution_detail } from "../execution-detail.js";

const props = defineProps(["executionDetails"]);

let testBasicDetails = ref([]);
// let customerLogoPath = ref("accionlabs-logo.png");
let customerLogoPath = ref("");

onMounted(() => {
  createHeaderChips();
  // testBasicDetails.value[0].count = processExecution(props.executionDetails);
  getCustomerHeaderLogo();
});

watch(() => props.executionDetails, () => {
  createHeaderChips();
  getCustomerHeaderLogo();
});

const onHeaderLogoErrorHandler = () => {
  customerLogoPath.value = "accionlabs-logo.png";
}

const getCustomerHeaderLogo = () => {
  if(props.executionDetails.customHeader) {
    const srcMatch = props.executionDetails.customHeader.match(/<img[^>]+src="([^">]+)"/);
    const imagePath = srcMatch ? srcMatch[1] : null;
    customerLogoPath.value = imagePath;
  }
}

const createHeaderChips = () => {
  testBasicDetails.value = [
    {
      name: "Scenario Passed",
      count: "",
      icon: "",
    },
    {
      name: "Total Steps",
      count: props.executionDetails.totalSteps,
      icon: "mdi-flag-checkered",
    },
    {
      name: "Executed Steps",
      count: props.executionDetails.executed,
      icon: "mdi-play-circle-outline",
    },
    {
      name: "Passed",
      count: props.executionDetails.passCount,
      icon: "mdi-checkbox-marked-circle",
    },
    {
      name: "Failed",
      count: props.executionDetails.failCount,
      icon: "mdi-close-circle",
    },
    {
      name: "Skipped",
      count: props.executionDetails.skippedCount,
      icon: "mdi-skip-next-outline",
    },
  ];

  testBasicDetails.value[0].count = processExecution(props.executionDetails);
}

const getChipColorClass = (title) => {
  switch (title) {
    case "Scenario Passed":
      return "bg-light-green";
    case "Total Steps":
      // return "bg-light-blue";
      return "totalSteps";
    case "Executed Steps":
      // return "bg-cyan";
      return "executedSteps";
    case "Passed":
      // return "bg-green";
      return "passed";
    case "Failed":
      // return "bg-red";
      return "failed";
    case "Skipped":
      // return "bg-grey";
      return "skipped";
    default:
      return "bg-blue-grey";
  }
};

const processExecution = (execution) => {
  let totalScenarios = 0;
  let passedScenarios = 0;

  const traverseExecutions = (execution) => {
    if (execution.executionLevel === "SCENARIO") {
      totalScenarios++;
      if (execution.passCount === execution.totalSteps) {
        passedScenarios++;
      }
    }

    if (execution.nestedExecutions && execution.nestedExecutions.length > 0) {
      execution.nestedExecutions.forEach((nestedExecution) => {
        traverseExecutions(nestedExecution);
      });
    }
  };

  traverseExecutions(execution);

  return `${passedScenarios}/${totalScenarios}`;
};
</script>

