<template>
  <v-data-table
    :headers="headers"
    :items="activities"
    item-value="name"
    class="elevation-1 activityTable"
    :item-class="getRowClass"
    show-expand
    hover
    v-model:expanded="expanded"
    :expanded.sync="expanded"
  >
    <!-- Main Table Row -->
    <template v-slot:[`item.name`]="{ item }">
      <div class="d-flex align-center">
        <span>{{ item.name }}</span>
      </div>
    </template>

    <template v-slot:[`item.successRate`]="{ item }">
      <span :class="item.successRate === '100.00 %' ? 'activity-passed' : 'activity-failed'">
        {{ item.successRate }}
      </span>
    </template>

    <template
      #item.data-table-expand="{ internalItem, item, isExpanded, toggleExpand }"
    >
      <td v-if="item.stepDetails.length > 0" class="text-start">
        <v-btn
          :icon="
            isExpanded(internalItem) ? 'mdi-chevron-up' : 'mdi-chevron-down'
          "
          @click="toggleExpand(internalItem)"
          class="v-data-table__expand-icon"
          variant="text"
          aria-label="activity table expand btn"
        >
        </v-btn>
      </td>
    </template>

    <!-- <template v-slot:[`data-table-expand`] v-if="isExpanded">
      <v-icon>mdi-chevron-up</v-icon>
    </template> -->

    <!-- Expanded Row Content -->
    <template v-slot:expanded-row="{ columns, item }">
      <tr v-if="item.stepDetails.length > 0">
        <!-- <td :colspan="columns.length - 1"> -->
        <td colspan="12">
          <v-row class="flex-wrap pa-2 mt-0 mb-0">
            <v-col
              v-for="(step, index) in item.stepDetails"
              :key="index"
              cols="12"
              md="12"
              lg="12"
              class="pa-1"
            >
              <v-card variant="outlined" class="d-flex align-left flex-column">
                <v-card-title class="errorCard">
                  <v-chip class="ma-2 rowNoChip" small>
                    Row No. {{ step.rowNum }}
                  </v-chip>
                  <span class="ml-2 text-truncate">{{ step.description }}</span>
                  <v-chip
                    :class="step.isPass ? 'pass-color' : 'fail-color'"
                    class="ma-2"
                    small
                  >
                    {{ step.isPass ? "Pass" : "Fail" }}
                  </v-chip>
                </v-card-title>
                <v-card-subtitle
                  v-if="step.nestedMessages.length > 0"
                  class="d-flex flex-wrap"
                >
                  <v-row
                    class="errorCardNestedMessage"
                    no-gutters
                    v-for="(message, idx) in step.nestedMessages"
                    :key="idx"
                  >
                    <v-col cols="12">
                      <div
                        v-if="message.file && message.fileType === 'image'"
                        class="succLogFile ml-3"
                      >
                        <v-icon left color="primary">mdi-image-outline</v-icon>
                        <a
                          :href="message.file"
                          target="_blank"
                          rel="noopener noreferrer"
                          aria-label="image link"
                        >
                          {{ message.file.split("\\").pop() }}
                        </a>
                      </div>
                      <div
                        v-if="message.file && message.fileType === 'video'"
                        class="succLogFile ml-3"
                      >
                        <v-icon left color="primary">mdi-video-outline</v-icon>
                        <a
                          :href="message.file"
                          target="_blank"
                          rel="noopener noreferrer"
                          aria-label="file link"
                        >
                          {{ message.file.split("\\").pop() }}
                        </a>
                      </div>
                      <div
                        v-if="message.file && message.fileType === 'alt'"
                        class="succLogFile ml-3"
                      >
                        <v-icon left color="primary">mdi-file-link-outline</v-icon>
                        <a
                          :href="message.file"
                          target="_blank"
                          rel="noopener noreferrer"
                          aria-label="file link"
                        >
                          {{ message.file.split("\\").pop() }}
                        </a>
                      </div>
                    </v-col>
                    <v-col cols="12" class="text-left">
                      <v-chip
                        class="ma-2 error-msg"
                        default
                        v-if="message.message.length > 0"
                      >
                        <span class="text-truncate">{{
                          truncateMessage(message.message)
                        }}</span>
                        <v-btn
                          icon
                          x-small
                          variant="plain"
                          @click="copyToClipboard(message.message)"
                          :title="'Copy full message'"
                          aria-label="copy content btn"
                        >
                          <v-icon>mdi-content-copy</v-icon>
                        </v-btn>
                        <!-- <template v-slot:append>
                          <v-btn
                            icon
                            x-small
                            variant="plain"
                            @click="copyToClipboard(message.message)"
                            :title="'Copy full message'"
                          >
                            <v-icon>mdi-content-copy</v-icon>
                          </v-btn>
                        </template> -->
                      </v-chip>
                    </v-col>
                  </v-row>
                </v-card-subtitle>
              </v-card>
            </v-col>
          </v-row>
        </td>
      </tr>
    </template>
  </v-data-table>
</template>

<script setup>
import { ref } from "vue";
import { toast } from "vue3-toastify";
// Define props
const props = defineProps(["activities"]);

// Headers for the table
const headers = ref([
  { title: "Activity", key: "name", align: "center" },
  { title: "Start Date/Time", key: "startDateAndTime", align: "center" },
  { title: "Duration", key: "duration", align: "center" },
  { title: "Total Steps", key: "totalSteps", align: "center" },
  { title: "Pass", key: "passCount", align: "center" },
  { title: "Fail", key: "failCount", align: "center" },
  { title: "Success %", key: "successRate", align: "center" },
]);

// Expanded rows tracking
const expanded = ref([]);

// Method to determine row class
const getRowClass = (item) => {
  return item.successRate !== "100.00 %" ? "error-row" : "";
};

const truncateMessage = (message) => {
  // Truncate the message to show a preview, with an ellipsis if it's too long
  const maxLength = 100;
  return message.length > maxLength
    ? message.substring(0, maxLength) + "..."
    : message;
};

const copyToClipboard = (text) => {
  // Function to copy text to clipboard
  navigator.clipboard.writeText(text).then(
    () => {
      toast.success("Copied to clipboard");
    },
    (err) => {
      toast.error("Failed to copy: " + err);
    }
  );
};
</script>

