<template>
  <v-card class="chart-card" max-width="100%" height="320px" elevation="6">
    <!-- <canvas id="drill-down-chart"></canvas> -->
    <Bar
      id="drill-down-chart"
      :options="chartOptions"
      :data="chartData"
      @click="onChartClickHandler"
      aria-label="Drill down chart for execution data"
    />
    <div class="reset-buttons">
      <span class="chart-instruction" v-if="currentExecution === 'EXECUTION'"
        >click on the chart above to drill down</span
      >
      <div class="chart-buttons" v-else>
        <v-btn
          size="small"
          density="comfortable"
          @click="executionBtnClickHandler"
          aria-label="chart reset"
          >Execution</v-btn
        >
        <v-btn
          size="small"
          density="comfortable"
          @click="backBtnClickHandler"
          class="ml-3"
          aria-label="chart back"
          >Back</v-btn
        >
      </div>
    </div>
  </v-card>
</template>

<script setup>
import { ref, onMounted } from "vue";
// import Chart from "chart.js/auto";
import { chartConfig, chartDatasetsConfig } from "../config/chart";
import { Bar } from "vue-chartjs";
import {
  Chart as ChartJS,
  Tooltip,
  Title,
  SubTitle,
  Legend,
  BarElement,
  CategoryScale,
  LinearScale,
  PointElement,
  LineElement,
  LineController,
} from "chart.js";

ChartJS.register(
  Tooltip,
  Title,
  SubTitle,
  Legend,
  BarElement,
  CategoryScale,
  LinearScale,
  PointElement,
  LineElement,
  LineController
);

const props = defineProps(["execution_detail"]);

let drillDownTracking = ref([]);
let current = ref(null);
let currentExecution = ref("EXECUTION");

let chartOptions = ref(null);
let chartData = ref({
  labels: [],
  datasets: [],
});

onMounted(() => {
  current.value = props.execution_detail;
  chartData.value = createChartData([props.execution_detail]);
  chartOptions.value = createChartOptions(props.execution_detail);
});

const createChartOptions = (obj) => {
  chartConfig.plugins.title.text = getHeading();
  chartConfig.plugins.subtitle.text = obj.executionLevel;
  return chartConfig;
};

const createChartData = (executionArray) => {
  const obj = {
    labels: [],
    passPercentage: [],
    failCount: [],
    passCount: [],
    totalSteps: [],
    skippedCount: [],
    duration: [],
  };

  executionArray.forEach((execution) => {
    if (
      execution.executionLevel == "ACTIVITY" ||
      execution.nestedExecutions.length > 0
    ) {
      obj.labels.push(execution.name);
      obj.passPercentage.push(
        (execution.passCount / execution.totalSteps) * 100
      );
      obj.failCount.push(execution.failCount);
      obj.passCount.push(execution.passCount);
      obj.totalSteps.push(execution.totalSteps);
      obj.skippedCount.push(execution.skippedCount);
      obj.duration.push(convertDuration(execution));
    }
  });

  return {
    labels: obj.labels,
    datasets: [
      { ...chartDatasetsConfig.passPercentage, data: obj.passPercentage },
      { ...chartDatasetsConfig.fail, data: obj.failCount },
      { ...chartDatasetsConfig.pass, data: obj.passCount },
      { ...chartDatasetsConfig.total, data: obj.totalSteps },
      { ...chartDatasetsConfig.skipped, data: obj.skippedCount },
      { ...chartDatasetsConfig.duration, data: obj.duration },
    ],
  };
};

const convertDuration = (refObj) => {
  const durationInMillisecs = refObj.endTime - refObj.startTime;
  const durationInMins = durationInMillisecs / (1000 * 60);
  // if(durationInMins < 1) {
  //   refObj.durationFormat = 'duration (sec)'
  //   return (durationInMillisecs / 1000).toFixed(3);
  // }
  // refObj.durationFormat = 'duration (min)'
  return durationInMins.toFixed(3);
};

const getHeading = () => {
  if (drillDownTracking.value.length > 0) {
    let headings = [props.execution_detail.name];
    let selectedExecution = props.execution_detail;

    drillDownTracking.value.forEach((ele) => {
      selectedExecution = selectedExecution.nestedExecutions[ele];
      headings.push(selectedExecution.name);
    });
    return headings.join(" - ");
  }
  return props.execution_detail.name;
};

const onChartClickHandler = (event, elements) => {
  const chartVal = ChartJS.getChart("drill-down-chart");

  let points = chartVal.getElementsAtEventForMode(
    event,
    "nearest",
    { intersect: true },
    true
  );
  if (points.length) {
    if (current.value.executionLevel === "SCENARIO") return;

    if (currentExecution.value !== "EXECUTION") {
      let currentIndex = points[0].index;

      current.value = current.value.nestedExecutions[currentIndex];

      currentExecution.value = current.value.nestedExecutions[0].executionLevel;
      drillDownTracking.value.push(currentIndex);
    } else {
      currentExecution.value = "SCRIPT";
    }
    chartData.value = createChartData(current.value.nestedExecutions);
    chartOptions.value = createChartOptions(current.value.nestedExecutions[0]);
  }
};

const executionBtnClickHandler = () => {
  currentExecution.value = "EXECUTION";
  current.value = props.execution_detail;

  drillDownTracking.value = [];
  chartData.value = createChartData([props.execution_detail]);
  chartOptions.value = createChartOptions(props.execution_detail);
};

const backBtnClickHandler = () => {
  if (!drillDownTracking.value.length) {
    executionBtnClickHandler();
    return;
  }

  drillDownTracking.value.pop();

  let selectedExecution = props.execution_detail;
  drillDownTracking.value.forEach((ele) => {
    selectedExecution = selectedExecution.nestedExecutions[ele];
  });

  current.value = selectedExecution;
  currentExecution.value = selectedExecution.nestedExecutions[0].executionLevel;

  chartData.value = createChartData(current.value.nestedExecutions);
  chartOptions.value = createChartOptions(current.value.nestedExecutions[0]);
};
</script>

