const allUniqueLogFiles = computed(() => {
  let resultLogs = {};
  function traverseExecution(execution) {
    if (Object.keys(execution.logs).length) {
      resultLogs = { ...resultLogs, ...execution.logs };
    }
    execution.nestedExecutions.forEach((nestedExecution) => {
      traverseExecution(nestedExecution);
    });
  }
  traverseExecution(props.executionDetailsAddedMoreProps);
  return resultLogs;
});

